historian.tables.activatePane_=function(pane){$("#panel-tables .tab-pane").removeClass("active in");$(pane.container).addClass("active in");$("#panel-tables .nav-tabs > li").removeClass("active");$(pane.tab).addClass("active");$(historian.tables.CONTAINER_SELECTOR).scrollTop(0)};historian.tables.jumpToSelector=function(pane,selector){historian.tables.activatePane_(pane);var top;if(selector=="*")top=0;else top=$(pane.container).find(selector).first().position().top-historian.tables.JUMP_OFFSET;$(historian.tables.CONTAINER_SELECTOR).scrollTop(top)};
